const run = async () => {
  try {
    if (!data.tag) { if (message) message.error("A tag is required — select an available tag from stock."); return Promise.reject(new Error("tag-required")); }

    var payload = {
      description: data.description,
      categoryId: (data.category ? (data.category.id || data.category) : null),
      mscoaClassId: (data.category ? (data.category.id || data.category) : null),
      subCategory: (data.subCategoryName || null),
      make: data.make,
      model: data.model,
      serialNo: data.serialNo,
      acquisitionType: data.acquisitionType,
      supplierId: (data.supplier ? (data.supplier.id || data.supplier) : null),
      acquisitionDate: data.acquisitionDate,
      acquisitionCost: data.acquisitionCost,
      usefulLifeMonths: data.usefulLifeMonths,
      accumulatedDepreciation: (Number(data.accumDepreciation) || 0),
      basPaymentRef: data.basPaymentRef,
      tagId: (data.tag ? (data.tag.id || data.tag) : null),
      conditionCode: data.conditionCode,
      custodianId: (data.custodian ? (data.custodian.id || data.custodian) : null),
      costCentreId: (data.costCentre ? (data.costCentre.id || data.costCentre) : null),
      siteId: (data.site ? (data.site.id || data.site) : null),
      locationId: (data.location ? (data.location.id || data.location) : null),
      binId: (data.bin ? (data.bin.id || data.bin) : null)
    };
    var res = await http.post('/api/services/AssetManagement/AssetRegistration/RegisterSingleAsset', payload);
    var assetNo = (res && res.data && res.data.result) ? res.data.result.assetNo : '';
    message.success('Asset registered & capitalised — ' + (assetNo || ''));
  } catch (e) { message.error((e && e.message) || 'Failed to register asset'); return Promise.reject(e); }
  return Promise.resolve();
};
return run();
